                                Voltar ao Login
                            </button>
                        </div>
                    </form>
                )}

                {step === 2 && foundUser && (
                    <form onSubmit={handleAnswerSubmit} className="space-y-4">
                        <div className="p-4 bg-blue-50 rounded-lg border border-blue-100">
                            <p className="text-xs font-bold text-blue-700 uppercase mb-1">Pergunta de Segurança</p>
